/* ── Curated Slide Content: Units 3 & 4 (Lessons 13-20) ── */

var SLIDES_U3U4 = {

  13: [
    { type: 'hook', title: 'Deepfakes and Disinformation', body: 'In 2024, a deepfake video of a multinational CEO announcing fake earnings wiped $25 billion from the company\'s stock price in 12 minutes before it was identified as synthetic. In the same year, AI-generated audio of a political leader was shared 50 million times before fact-checkers could respond. Deepfake technology has advanced from obvious fakes to near-perfect synthetic media — and detection is losing the arms race against generation.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">$25B</span><span class="sl">wiped from stock price by one deepfake video</span></div><div class="hook-stat-mini"><span class="sv">50M</span><span class="sl">shares of AI audio before fact-checkers responded</span></div><div class="hook-stat-mini"><span class="sv">3 sec</span><span class="sl">of audio needed to clone a voice convincingly</span></div><div class="hook-stat-mini"><span class="sv">Free</span><span class="sl">tools can deepfake from a single photo in minutes</span></div></div>' },
    { type: 'concept', title: 'How Deepfakes Work', body: 'Deepfakes use deep learning — specifically generative adversarial networks (GANs) and diffusion models — to create synthetic media that is increasingly indistinguishable from authentic content. The 2023 Hong Kong incident, where a CFO was defrauded of £20 million after a deepfake video call impersonating his CEO, shows these are not hypothetical risks.', bullets: ['GANs pit two neural networks against each other: a generator creates fakes, a discriminator tries to detect them — each iteration sharpens both', 'Face-swapping: Maps one person\'s facial expressions onto another\'s face in video, frame by frame', 'Voice cloning: ElevenLabs and similar tools can clone a voice from as little as 3 seconds of audio', 'Text-to-video: OpenAI\'s Sora (2024) generates photorealistic video from text descriptions alone', 'Accessibility collapse: In 2019, deepfakes required expensive GPUs and hours of footage — today, free apps work from a single photo in minutes'], callout: 'In 2019, creating a convincing deepfake required hours of footage and expensive hardware. Today, free apps can do it from a single photo in minutes.' },
    { type: 'concept', title: 'Detection and Defence', body: 'As deepfakes improve, detection methods struggle to keep pace. The C2PA (Coalition for Content Provenance and Authenticity) standard — backed by Adobe, Microsoft, and Google — offers a promising technical solution, but requires industry-wide adoption to work.', bullets: ['Technical detection: AI models trained to spot artefacts — unnatural blinking rates, skin texture inconsistencies, lighting discontinuities', 'C2PA provenance: Embeds cryptographic metadata proving where and when content was originally captured — like a tamper-evident seal', 'Google SynthID: Invisible watermarks embedded into AI-generated content that survive compression and cropping', 'Media literacy: Teaching SIFT (Stop, Investigate, Find better coverage, Trace claims) before sharing', 'The liar\'s dividend: Even real videos can now be dismissed as deepfakes — undermining all visual evidence'], callout: 'Current deepfake detectors achieve about 65-85% accuracy on the latest generation models — barely better than a coin flip on the most sophisticated fakes.' },
    { type: 'activity', title: 'Spot the Fake', instructions: 'Use the Deepfake Detection Checklist from Resources to analyse a set of real and synthetic media samples.', steps: ['Your teacher will provide 6 media samples — some real, some AI-generated', 'For each sample, work through the Deepfake Detection Checklist systematically', 'Look for: unnatural blinking, inconsistent lighting, warped edges, audio-lip sync issues', 'Record your verdict for each: Real, Fake, or Unsure', 'Compare results with the class — what was your accuracy rate?', 'Discuss: Which fakes were hardest to detect and why?'] },
    { type: 'discussion', title: 'Truth in a Post-Truth World', questions: [{ num: 1, text: 'If anyone can create convincing fake video of anyone saying anything, what happens to the concept of evidence?' }, { num: 2, text: 'Should creating deepfakes be illegal, or only sharing them? How would you enforce such a law?' }, { num: 3, text: 'The "liar\'s dividend": Now that deepfakes exist, real video can be dismissed as fake. How do we combat this?' }] },
    { type: 'scenario', title: 'The Viral Video', situation: 'You have 22,000 Twitter/X followers interested in politics. At 11pm, a video appears showing a senior government minister "admitting" to accepting bribes. It already has 800,000 views. Your phone is buzzing with friends telling you to share it. The video looks convincing — right lighting, realistic voice, natural mannerisms. But you notice the source account was created three days ago.', question: 'What do you do?', choices: [ { text: 'Share immediately — 800K people can\'t all be wrong, and this is too important to ignore', outcome: 'By morning, the video is confirmed as a deepfake created by a foreign influence operation. Your name appears in news articles listing accounts that amplified disinformation. You\'ve lost 3,000 followers and your credibility on political topics is permanently damaged.' }, { text: 'Reverse image search the source account, check BBC/Reuters for coverage, and wait 30 minutes before deciding', outcome: 'You find no credible outlet has covered the story. A Reuters fact-check appears 20 minutes later confirming it\'s synthetic. You share the fact-check instead. Your followers thank you for responsible sourcing — three journalists follow you the next day.' }, { text: 'Share with a warning: "Unverified — may be a deepfake. Sharing for discussion"', outcome: 'Your caveat gets stripped as others screenshot and reshare the original video without your warning. You still contributed to the spread. Platform analytics show your share drove 12,000 additional views before the video was taken down.' } ] },
    { type: 'quiz', question: 'What is the minimum a deepfake typically requires to convincingly replicate someone\'s face?', options: ['Thousands of hours of video footage', 'A full 3D scan of the person\'s face', 'A relatively small amount of source images or video', 'The person\'s explicit consent and cooperation'], correct: 2, explanation: 'Modern deepfake technology can produce convincing results with minimal source material — even a few photos or short video clips can be enough. This accessibility is what makes deepfakes such a significant societal risk.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🎭', label: 'Technology is advancing fast', text: 'Deepfakes now require minimal source material and can be created with free tools in minutes' }, { icon: '🔍', label: 'Detection is struggling', text: 'AI detectors achieve 65-85% accuracy — provenance standards (C2PA) and SIFT media literacy are essential' }, { icon: '⚠️', label: 'The liar\'s dividend', text: 'Deepfakes don\'t just spread lies — they allow real evidence to be dismissed as fake, undermining all trust in visual media' }] }
  ],

  14: [
    { type: 'hook', title: 'Surveillance and Facial Recognition', body: 'London has over 940,000 CCTV cameras — one for every 10 residents. China\'s SkyNet system covers over 600 million cameras with real-time facial recognition. In 2020, Robert Williams, a Black man in Detroit, was wrongfully arrested after facial recognition software misidentified him. He spent 30 hours in custody for a crime he did not commit. The technology promises safety but delivers a complex trade-off between security and civil liberties.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">940K</span><span class="sl">CCTV cameras in London — 1 per 10 residents</span></div><div class="hook-stat-mini"><span class="sv">100×</span><span class="sl">higher error rate for dark-skinned women vs. white men (NIST)</span></div><div class="hook-stat-mini"><span class="sv">30 hrs</span><span class="sl">Robert Williams held after wrongful AI misidentification</span></div><div class="hook-stat-mini"><span class="sv">600M+</span><span class="sl">cameras in China\'s SkyNet system</span></div></div>' },
    { type: 'concept', title: 'How Facial Recognition Works', body: 'Facial recognition systems convert faces into mathematical representations (faceprints) and compare them against databases. The NIST (National Institute of Standards and Technology) 2019 Face Recognition Vendor Test evaluated 189 algorithms and found staggering disparities in accuracy across demographic groups.', bullets: ['Detection: Identifies that a face exists in an image or video frame', 'Alignment: Normalises the face to a standard orientation and scale', 'Feature extraction: Maps facial geometry — inter-eye distance, jaw contour, nose bridge — into a numeric vector (faceprint)', 'Matching: Compares the faceprint against enrolled database entries using cosine similarity scores', 'Accuracy gap: 99.7% accuracy for white males vs. 65.3% for dark-skinned females — not a glitch, a structural flaw in biased training data'], callout: 'The performance gap is not a bug — it reflects training data that is overwhelmingly composed of lighter-skinned faces. Bias is baked into the technology.' },
    { type: 'concept', title: 'The Surveillance Debate', body: 'Facial recognition in public spaces creates a fundamental tension between collective security and individual privacy. The 2023 Kings Cross case — where a London property developer secretly ran facial recognition on 250,000 pedestrians — shows how quickly function creep occurs without regulation.', bullets: ['For surveillance: Identifies wanted criminals in crowds, locates missing persons, deters terrorism, speeds up airport security', 'Against surveillance: Creates chilling effects — people modify behaviour, avoid protests, self-censor when watched', 'Function creep: Technology deployed for counter-terrorism expands to policing minor offences, tracking journalists, monitoring employees', 'Disproportionate impact: Marginalised communities face higher false positive rates AND heavier baseline surveillance', 'Accountability gap: Most UK surveillance systems are deployed without parliamentary approval, judicial oversight, or public consultation'], callout: 'San Francisco banned government facial recognition in 2019. The EU AI Act classifies real-time biometric surveillance in public spaces as "unacceptable risk." The UK has no equivalent legal restriction.' },
    { type: 'activity', title: 'Surveillance Policy Design', instructions: 'Your group represents a city council deciding whether to deploy facial recognition cameras in your city centre. Use the Surveillance Debate Pack from Resources.', steps: ['Split into three teams: Security advocates, Civil liberties advocates, and the Council', 'Security team: Prepare a 3-minute case for deploying facial recognition with specific safeguards', 'Civil liberties team: Prepare a 3-minute case against deployment with alternative safety proposals', 'Both teams present to the Council', 'Council asks questions and deliberates', 'Council votes and announces their decision with reasoning'] },
    { type: 'discussion', title: 'Where Do You Draw the Line?', questions: [{ num: 1, text: 'Would you accept facial recognition in your school if it made the building safer? What about your neighbourhood?' }, { num: 2, text: 'If the accuracy gap between demographic groups cannot be fully closed, should the technology be deployed at all?' }, { num: 3, text: 'China uses facial recognition to monitor ethnic minorities in Xinjiang. At what point does surveillance become oppression?' }] },
    { type: 'scenario', title: 'The School Safety Proposal', situation: 'Your school\'s headteacher has proposed installing facial recognition cameras at all entrances. The stated purpose: to identify banned visitors and protect students from safeguarding threats. The system will match faces against a database of individuals with court-issued exclusion orders. A local newspaper has already reported on it, and parents are divided. You are a student governor with a vote on the proposal.', question: 'How do you vote — and what conditions, if any, would you require?', choices: [ { text: 'Vote yes — safeguarding is paramount and the benefits to student safety outweigh privacy concerns', outcome: 'The system is installed. Six months later, a Year 9 student of Somali heritage is incorrectly flagged as a known offender and held at the entrance for 25 minutes. Their parents file a formal complaint. The reputational damage forces a review.' }, { text: 'Vote no — the safeguarding risk can be addressed through other means (visitor ID checks, entry codes, trained staff)', outcome: 'The proposal is rejected. You propose a human-led visitor verification protocol instead. It costs less, requires no data retention, and a staff review 12 months later finds it has prevented three safeguarding incidents — the same figure the facial recognition supplier had projected.' }, { text: 'Vote yes, but only with strict conditions: independent audit, demographic accuracy testing, data deleted within 24 hours, annual review', outcome: 'The conditions are accepted but the supplier cannot meet the accuracy testing requirement. The system is never deployed. The headteacher credits your conditions with exposing a vendor making overclaims about performance.' } ] },
    { type: 'quiz', question: 'According to NIST studies, facial recognition error rates for dark-skinned women can be up to how many times higher than for light-skinned men?', options: ['5 times higher', '10 times higher', '50 times higher', '100 times higher'], correct: 3, explanation: 'NIST studies found error rates up to 100 times higher for dark-skinned women than white men in some commercial systems — a disparity that has led to wrongful arrests and calls for moratoriums on the technology.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '📷', label: 'Unequal accuracy', text: 'Facial recognition error rates are up to 100x higher for dark-skinned women than light-skinned men — bias baked into training data' }, { icon: '⚖️', label: 'Security vs. liberty', text: 'Genuine safety benefits must be weighed against chilling effects on protest, expression, and movement' }, { icon: '🏛️', label: 'Regulation gap', text: 'The EU bans real-time biometric surveillance in public; the UK has no equivalent law — leaving deployment largely unchecked' }] }
  ],

  15: [
    { type: 'hook', title: 'The Environmental Cost', body: 'Training GPT-4 is estimated to have consumed as much electricity as 120 US homes use in an entire year. A single ChatGPT query uses roughly 10 times the energy of a Google search. The IEA\'s 2024 report found that global AI data centre electricity demand is already equivalent to that of the Netherlands — and is expected to double again by 2026. Microsoft\'s carbon emissions rose 30% between 2020 and 2024 due to AI infrastructure expansion — directly contradicting its 2030 carbon-negative pledge. At the same time, AI is being used to optimise energy grids, accelerate climate research, and design more efficient materials. Is AI a climate villain or a climate hero? The answer is: both.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">10×</span><span class="sl">more energy per ChatGPT query vs. a Google search</span></div><div class="hook-stat-mini"><span class="sv">552t</span><span class="sl">CO₂ emitted training GPT-3 alone</span></div><div class="hook-stat-mini"><span class="sv">30%</span><span class="sl">rise in Microsoft\'s carbon emissions 2020–2024 due to AI</span></div><div class="hook-stat-mini"><span class="sv">2×</span><span class="sl">AI data centre energy demand expected to double again by 2026 (IEA)</span></div></div>' },
    { type: 'concept', title: 'The Carbon Cost of AI', body: 'AI\'s environmental footprint comes from three sources: training models, running inference, and the hardware lifecycle. A 2023 University of Massachusetts study found that training a single large language model can emit more CO₂ than five average American cars over their entire lifetimes — including manufacture.', bullets: ['Training: GPT-3 training emitted ~552 tonnes of CO2 — equivalent to 120 cars driving for a year. GPT-4 is estimated to be 10x larger. By contrast, DeepSeek R1 (Jan 2025) achieved comparable performance at a fraction of the training cost — but raised questions about whether cheaper training means much more AI being run overall', 'Inference: Every query has a cost. ChatGPT reaching 300 million weekly users by early 2025 means millions of energy-consuming queries every minute, continuously', 'Water: Microsoft\'s Iowa data centre consumed 6 million litres of water per day for cooling — and Microsoft\'s water consumption rose 34% between 2021 and 2023 due to AI expansion', 'Hardware: NVIDIA H100 and Blackwell GPUs require rare earth minerals (cobalt, lithium), energy-intensive chip fabrication, and generate e-waste at accelerating rates', 'The efficiency paradox: DeepSeek showed AI can be trained more cheaply — but Jevons\' paradox suggests cheaper AI will be used far more, potentially increasing total energy use rather than reducing it'], callout: 'Google\'s total carbon emissions rose 48% from 2019 to 2023, and Microsoft\'s rose 30% from 2020 to 2024 — both driven by AI infrastructure. Both had pledged to be carbon neutral or negative by 2030.' },
    { type: 'concept', title: 'AI as Climate Solution', body: 'Despite its footprint, AI offers transformative potential for environmental sustainability. DeepMind\'s 2023 GNoME model discovered 2.2 million new crystal structures — including 380,000 stable materials that could unlock better batteries and solar cells — in days rather than the centuries traditional research would require.', bullets: ['Energy grid optimisation: DeepMind\'s AI reduced Google data centre cooling energy by 40% — equivalent to removing a power plant from the grid', 'Climate modelling: GraphCast (DeepMind, 2023) produces 10-day weather forecasts in under a minute — 100x faster than traditional physics models', 'Materials science: GNoME discovered more stable inorganic materials in one run than scientists found in all of recorded history', 'Precision agriculture: Satellite-AI systems reduce water use by 30% and pesticide application by 50% on monitored farms', 'Deforestation: Global Forest Watch uses AI satellite analysis to detect illegal logging within 24 hours across 70 countries'], callout: 'The net equation: If AI\'s climate solutions save more emissions than AI itself produces, the technology is net-positive. But this is not guaranteed — it depends entirely on deployment choices.' },
    { type: 'activity', title: 'Carbon Calculator', instructions: 'Estimate the environmental impact of your personal AI use and propose a sustainability strategy. Use the AI Environmental Impact Factsheet from Resources.', steps: ['List every AI service you use regularly (ChatGPT, Copilot, Midjourney, etc.)', 'Using the Factsheet, estimate the energy per query for each service', 'Estimate your total queries per week and calculate your monthly AI carbon footprint', 'Research: What is your AI provider doing about sustainability?', 'Propose 3 changes you could make to reduce your AI environmental impact', 'Design a one-page "Sustainable AI Use" policy for your school'] },
    { type: 'discussion', title: 'The Green AI Dilemma', questions: [{ num: 1, text: 'Should AI companies be required to disclose the carbon footprint of their models? Should users see a "carbon cost" per query?' }, { num: 2, text: 'Is it ethical to train ever-larger models when smaller, more efficient models might be good enough?' }, { num: 3, text: 'If AI can solve climate change faster, does its own carbon cost become an acceptable trade-off?' }] },
    { type: 'scenario', title: 'The Model Choice', situation: 'You are a product manager at a health startup building an AI tool that helps patients understand their test results. You have two options. Option A: GPT-4-class model — state-of-the-art accuracy, runs on cloud servers consuming roughly 0.01 kWh per query. Option B: A smaller, fine-tuned open-source model running on your own green-energy servers — 95% as accurate, consumes 0.0005 kWh per query. Your product will handle 2 million queries per month.', question: 'Which model do you choose — and how do you justify it to stakeholders?', choices: [ { text: 'Option A — patients deserve the most accurate medical AI possible. The energy difference is marginal at our scale', outcome: 'At 2M queries/month, Option A uses 20,000 kWh/month vs. 1,000 kWh for Option B. Over a year, you\'ve emitted roughly 11 additional tonnes of CO₂. A competitor launches with Option B, markets their green credentials, and wins a hospital contract you were shortlisted for.' }, { text: 'Option B — 95% accuracy is clinically sufficient, the energy savings are enormous, and our green data helps with NHS procurement criteria', outcome: 'You save 228,000 kWh per year — equivalent to taking 12 cars off the road. The accuracy gap proves negligible in real-world use (the 5% gap was on edge cases not typical of your patient queries). Your sustainability story helps close three enterprise deals.' }, { text: 'Run a 3-month clinical trial comparing both models on real patient queries before committing', outcome: 'The trial confirms the 5% gap is real but concentrated in rare diagnostic edge cases. You deploy Option B for routine queries and Option A for flagged high-risk results — a hybrid approach that balances accuracy and sustainability better than either option alone.' } ] },
    { type: 'quiz', question: 'Roughly how much more energy does a single ChatGPT query use compared to a standard Google search?', options: ['About the same', 'About 3 times more', 'About 10 times more', 'About 100 times more'], correct: 2, explanation: 'A single ChatGPT query uses approximately 10 times the energy of a standard Google search. At scale — with 100+ million daily users — this translates to enormous aggregate energy consumption.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '⚡', label: 'Massive energy footprint', text: 'Training GPT-3 emitted 552 tonnes of CO₂ — Google\'s emissions rose 48% in four years due to AI expansion' }, { icon: '🌱', label: 'Transformative climate potential', text: 'DeepMind\'s GNoME found more stable materials in one run than all of scientific history — AI can accelerate climate solutions' }, { icon: '📊', label: 'Deployment is the decision', text: 'Whether AI is net-positive for the climate depends on the choices engineers and product managers make' }] }
  ],

  16: [
    { type: 'hook', title: 'Global Regulation', body: 'The EU AI Act is now fully in force — with banned practices active from February 2025 and rules for AI models like GPT-4 from August 2025. The US reversed course: Trump revoked Biden\'s AI Executive Order on day one of his second term and pivoted to deregulation. The UK launched a £14bn AI investment plan in January 2025 but still has no AI-specific law. China has layered deepfake labelling rules on top of earlier algorithmic regulations. Four major powers, four fundamentally different approaches — and they are diverging, not converging.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">459</span><span class="sl">pages in the final EU AI Act text</span></div><div class="hook-stat-mini"><span class="sv">Feb 2025</span><span class="sl">EU\'s banned AI practices took effect</span></div><div class="hook-stat-mini"><span class="sv">Day 1</span><span class="sl">Trump revoked Biden\'s AI Executive Order (January 2025)</span></div><div class="hook-stat-mini"><span class="sv">€35M</span><span class="sl">max fine for breaching EU AI Act rules</span></div></div>' },
    { type: 'concept', title: 'Four Regulatory Models', body: 'Understanding the major global approaches reveals fundamentally different philosophies about the role of government in technology governance. The EU AI Act — in force since August 2024, with prohibited practices banned from February 2025 and GPAI model rules active from August 2025 — is the world\'s first comprehensive AI law. But it sat in draft for three years while ChatGPT, Midjourney, and Sora all launched without it.', bullets: ['EU AI Act (fully active 2025): Risk tiers — unacceptable (banned: social scoring, real-time biometric surveillance in public), high-risk (transparency, human oversight, audit trails required), limited-risk, and minimal-risk. GPAI models like GPT-4 and Gemini face new systemic risk obligations from August 2025', 'US approach: Biden\'s 2023 Executive Order on AI was revoked by President Trump on day one of his second term (January 2025), replaced by an EO prioritising AI "freedom" and competitiveness. No comprehensive federal AI law exists; sector agencies (FDA, SEC) regulate AI in their domains only', 'UK approach: The 2025 AI Opportunities Action Plan committed £14bn in AI investment and expanded the AI Safety Institute\'s mandate. Still no AI-specific legislation — existing regulators (ICO, Ofcom, FCA) apply current law, but a proposed AI bill is under consultation', 'China approach: Algorithmic Recommendation Regulation (2022), Generative AI Measures (2023), and new deepfake labelling rules (2025) layer up controls. State deploys AI extensively for internal security and surveillance'], callout: 'The EU regulates to protect citizens. The US (under Trump) deregulates to accelerate competitiveness. The UK tries to balance both. China regulates to maintain state control.' },
    { type: 'concept', title: 'The Regulation Dilemma', body: 'Every regulatory approach involves trade-offs. Too little regulation risks harm; too much risks stifling innovation and falling behind competitors. The Brussels Effect — where EU standards become global defaults — is the most powerful dynamic in technology governance today. But the US pivot to deregulation under Trump in 2025 is now testing whether that effect still holds.', bullets: ['The Brussels Effect: Companies find it easier to comply everywhere with EU standards than to build separate systems per jurisdiction. GDPR became a global privacy benchmark the same way — AI Act may follow, or the US deregulatory push may fracture this', 'Speed mismatch: The EU AI Act took 3 years to pass. In that period: ChatGPT launched (Nov 2022), DALL-E 2 went public, Sora was demonstrated, GPT-4 was released — and DeepSeek R1 (Jan 2025) upended assumptions about AI development costs', 'Audit challenge: Auditing an AI system requires access to training data, model weights, and evaluation results — most companies treat these as trade secrets. The EU is now demanding this access from GPAI providers', 'Regulatory arbitrage: The US deregulatory pivot in 2025 has intensified competition — EU companies are lobbying for delays in enforcement while US rivals face fewer constraints', 'Enforcement gap: The EU has 27 member states but the AI Office in Brussels is only now building its enforcement capacity — first major GPAI investigations began in 2025'], callout: 'The EU AI Act is the first law in force, but the US-EU regulatory divergence in 2025 may become the defining tension in global AI governance. Whether European rules become the global standard — or an isolated outlier — will be decided in the next few years.' },
    { type: 'activity', title: 'Regulation Jigsaw', instructions: 'Using the Regulation Jigsaw Cards from Resources, become an expert on one regulatory approach and teach it to your group.', steps: ['Form groups of 4. Each person takes one jurisdiction: EU, US, UK, or China', 'Using the Jigsaw Cards, become an expert on your jurisdiction (10 minutes)', 'Return to your group and teach the others about your approach (3 minutes each)', 'As a group, create a comparison table: Strengths, Weaknesses, and Key Differences', 'Vote: Which approach would you adopt for a new country? Justify your choice', 'Present your group\'s recommendation to the class'] },
    { type: 'discussion', title: 'Governing the Ungovernable?', questions: [{ num: 1, text: 'Should there be a single global AI regulatory framework, similar to international aviation rules? In 2025, the US and EU diverged sharply — does this make global standards more or less realistic?' }, { num: 2, text: 'The UK\'s AI Opportunities Action Plan (2025) committed £14bn in investment while still having no AI-specific law. Is this a good balance — or a race to the bottom?' }, { num: 3, text: 'Trump revoked Biden\'s AI Executive Order on day one of his second term. What does it say about AI policy that a major country\'s entire regulatory approach can change overnight with a new government?' }] },
    { type: 'scenario', title: 'The Startup Decision', situation: 'You\'ve co-founded an AI recruitment tool that screens CVs and ranks candidates. Your tool is trained on 10 years of hiring data from 200 UK companies. It works well — but an internal audit reveals it ranks women 12% lower than men with equivalent qualifications, likely because historical hiring data reflects past discrimination. You need to decide your market strategy before your Series A pitch next week.', question: 'How do you proceed?', choices: [ { text: 'Launch in the US first — no AI-specific law, fastest route to market, lower compliance cost', outcome: 'You launch, grow fast. Eighteen months later a ProPublica-style investigation identifies the gender bias. Three class action lawsuits are filed in California. The legal fees exceed your Series A raise. Two board members resign. You\'re now fixing a problem that was identified before launch.' }, { text: 'Pause launch, fix the gender bias, then pursue EU certification — slower but you\'ll be compliant from day one', outcome: 'The 4-month delay costs you one competitor deal. But your EU compliance documentation becomes your strongest selling point to HR teams worried about legal liability. You close a £2M NHS contract specifically because you can demonstrate algorithmic fairness audits.' }, { text: 'Disclose the bias in your terms of service and let customers decide — transparency, not paternalism', outcome: 'The ICO investigates after a journalist reads your T&Cs. They rule that disclosing discrimination does not make it lawful under the Equality Act 2010. You are fined and ordered to withdraw the tool from the UK market pending a full audit.' } ] },
    { type: 'quiz', question: 'What approach does the EU AI Act take to regulating artificial intelligence?', options: ['A complete ban on AI in public services', 'A risk-based classification system (unacceptable, high, limited, minimal)', 'Voluntary guidelines with no enforcement', 'Regulation only of military AI applications'], correct: 1, explanation: 'The EU AI Act classifies AI systems by risk level: unacceptable uses are banned (e.g. social scoring), high-risk systems face strict requirements, limited-risk needs transparency, and minimal-risk is unregulated.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🇪🇺', label: 'Four diverging philosophies', text: 'EU (protect citizens, fully active 2025), US (deregulate under Trump 2025), UK (invest and wait), China (layer controls) — diverging, not converging' }, { icon: '⏱️', label: 'Regulation always lags', text: 'The EU AI Act took 3 years — and even now, models like DeepSeek R1 are forcing regulators to rethink assumptions built into the text' }, { icon: '🌍', label: 'The Brussels Effect under pressure', text: 'EU standards have become global defaults before — but the US deregulatory pivot in 2025 is the biggest challenge yet to that pattern' }] }
  ],

  17: [
    { type: 'hook', title: 'Analysing the Status Quo', body: 'A 2024 survey found that 89% of UK universities now have an AI policy — but only 23% of students had actually read it. Meanwhile, 67% of students admitted to using AI tools regularly for coursework. The gap between policy and practice is enormous. Before you can write better policy, you need to understand what already exists, what works, and what fails. Today, you become policy auditors.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">89%</span><span class="sl">of UK universities have an AI policy</span></div><div class="hook-stat-mini"><span class="sv">23%</span><span class="sl">of students had actually read it</span></div><div class="hook-stat-mini"><span class="sv">67%</span><span class="sl">of students use AI tools for coursework regularly</span></div><div class="hook-stat-mini"><span class="sv">Nov 22</span><span class="sl">ChatGPT launched — most policies were written after this</span></div></div>' },
    { type: 'concept', title: 'Policy Audit Framework', body: 'Evaluating AI policies requires a structured approach. A good audit examines not just what a policy says, but how practical, enforceable, and fair it is. The Russell Group universities published a joint AI principles statement in 2023 — but each institution still interprets these principles differently.', bullets: ['Scope: What does the policy cover? Does it address generative AI specifically, or only plagiarism generally?', 'Clarity: Can a typical student understand the rules without reading a glossary? Test it on a Year 12 student', 'Enforceability: How are violations detected? Turnitin AI detection has a 9% false positive rate — flagging human work as AI', 'Fairness: Does the policy disadvantage non-native English speakers, who use AI grammar tools more heavily?', 'Currency: When was it last reviewed? November 2022 (ChatGPT launch) is the key milestone — anything before is probably outdated'], callout: 'Many school AI policies were written before ChatGPT launched in November 2022. A policy that does not mention generative AI is already outdated.' },
    { type: 'concept', title: 'Common Policy Gaps', body: 'Research reveals recurring weaknesses in existing AI policies across education. A 2024 review by Jisc (the UK higher education technology body) found these five failure patterns repeated across 60 institutions.', bullets: ['Binary thinking: "AI is banned" or "AI is allowed" — no nuance for brainstorming vs. writing vs. proofreading vs. generating', 'Tool-specific rules: "ChatGPT is prohibited" — but what about Copilot, Grammarly, Gemini, or AI embedded in Word?', 'No disclosure mechanism: Students do not know when, how, or in what format to declare AI use', 'Assessment gap: Policies do not explain how AI use affects grades — does using AI for structure reduce your mark?', 'One-way policies: Rules for students but no equivalent guidance for teachers using AI to generate worksheets and feedback'], callout: 'The best policies focus on principles (transparency, academic integrity, critical thinking) rather than specific tools — because tools change faster than policies can be updated.' },
    { type: 'activity', title: 'Policy Audit Workshop', instructions: 'Audit a real university or school AI policy using the University AI Policy Comparison resource and the audit framework above.', steps: ['Your teacher will provide 2-3 real AI policies from UK universities or schools', 'Using the audit framework, score each policy on: Scope, Clarity, Enforceability, Fairness, and Currency', 'Rate each criterion from 1 (poor) to 5 (excellent) with written justification', 'Identify the top 3 strengths and top 3 weaknesses across all policies', 'Write 3 specific recommendations for improvement', 'Compare findings with another pair — did you identify the same issues?'] },
    { type: 'discussion', title: 'Policy in Practice', questions: [{ num: 1, text: 'Why do you think most students have not read their institution\'s AI policy? How could this be fixed?' }, { num: 2, text: 'Should AI policies be written by administrators, teachers, students, or all three? Why?' }, { num: 3, text: 'Is it possible to write an AI policy that is both strict enough to maintain academic integrity and flexible enough to encourage learning with AI?' }] },
    { type: 'scenario', title: 'The Flagged Essay', situation: 'Mr Chen is a sixth-form English teacher. His AI detection tool (Turnitin) has flagged a student\'s essay as "87% likely AI-generated." The student — Amara, a hardworking student who moved from Nigeria two years ago — says she used Grammarly to fix grammar and asked ChatGPT one question about essay structure, but wrote every word herself. Her previous essays show a similar style. Turnitin\'s false positive rate for non-native speakers is estimated at 15-20%.', question: 'What should Mr Chen do?', choices: [ { text: 'Trust the tool — an 87% confidence rating is compelling evidence. Refer Amara for academic misconduct investigation', outcome: 'The misconduct panel reviews Amara\'s draft history (she has timestamped Google Docs going back 6 weeks) and her previous essays. They find no evidence of AI authorship. The false accusation has damaged trust, caused Amara significant distress, and prompted three parents to write to the headteacher about the reliability of AI detection.' }, { text: 'Disregard the flag — Amara is a trustworthy student. Give her the mark she earned', outcome: 'The essay is graded normally. However, you have no documented process for how you reached this decision. If another teacher makes the opposite call on a similar case, the inconsistency opens the school to an equality challenge.' }, { text: 'Have a private conversation with Amara, review her Google Docs draft history and browser history, and make a holistic judgment based on all available evidence — not the tool alone', outcome: 'The draft history shows 14 revision sessions over 3 weeks, with clear human editing patterns. You note in her file that the AI detection flag was investigated and not substantiated. You also report the false positive to your head of department, which triggers a school-wide review of the Turnitin policy.' } ] },
    { type: 'quiz', question: 'What is the most common weakness found when auditing existing school AI policies?', options: ['They are too long and detailed', 'They focus on principles rather than tools', 'They use binary thinking — blanket bans or no rules at all', 'They update too frequently'], correct: 2, explanation: 'Many school AI policies fall into binary thinking — either banning AI entirely or having no restrictions. Effective policies address the spectrum of AI use and focus on transferable principles rather than specific tool names.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '📋', label: 'Audit before you build', text: 'Understanding what exists — and what fails — is essential before writing new policy' }, { icon: '🔍', label: 'Five recurring gaps', text: 'Binary thinking, tool-specific bans, no disclosure mechanism, assessment disconnect, and one-way rules' }, { icon: '🎯', label: 'Principles over tools', text: 'Tool names become obsolete; principles like transparency and integrity remain relevant as AI evolves' }] }
  ],

  18: [
    { type: 'hook', title: 'Defining Acceptable Use', body: 'A student uses ChatGPT to brainstorm essay ideas. Acceptable? Most say yes. A student uses ChatGPT to write their entire essay. Unacceptable? Most say yes. But what about using AI to improve grammar? To restructure paragraphs? To generate a first draft that they then rewrite? The line between acceptable and unacceptable AI use is not a line at all — it is a spectrum. Today, your class will collaboratively define where the boundaries should be.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">5</span><span class="sl">levels of AI use in education — from inspiration to authorship</span></div><div class="hook-stat-mini"><span class="sv">IB</span><span class="sl">now allows AI use with disclosure — a landmark policy shift</span></div><div class="hook-stat-mini"><span class="sv">Level 3</span><span class="sl">is where most educators disagree — AI drafts you rewrite</span></div><div class="hook-stat-mini"><span class="sv">100%</span><span class="sl">of policies that work require disclosure, whatever the rules</span></div></div>' },
    { type: 'concept', title: 'The Spectrum of AI Use', body: 'AI use in education exists on a spectrum from fully independent work to fully AI-generated work. The International Baccalaureate\'s 2023 policy shift — treating AI like a calculator, allowed with disclosure — marked a turning point in how educational institutions worldwide think about this spectrum.', bullets: ['Level 0: No AI used — entirely human work, as assessed in traditional exams', 'Level 1: AI as inspiration — brainstorming essay angles, checking understanding, generating reading lists', 'Level 2: AI as editor — Grammarly-style grammar fixing, structural suggestions, vocabulary improvement', 'Level 3: AI as collaborator — generating a first draft the student substantially rewrites and critiques (the contested zone)', 'Level 4: AI as author — submitting AI-generated work with minimal editing (universally considered academic misconduct)'], callout: 'Most educators agree Level 0-2 is acceptable and Level 4 is not. The real debate is Level 3 — and a policy that does not address it leaves students and staff guessing.' },
    { type: 'concept', title: 'Balancing Innovation and Integrity', body: 'An effective acceptable use policy must balance two competing goals: encouraging students to develop AI skills they will need professionally, while maintaining academic integrity and equity. The World Economic Forum\'s 2023 Future of Jobs report found AI literacy is now the number one skill gap in graduate recruitment.', bullets: ['The skills argument: Students who cannot use AI effectively will be disadvantaged vs. peers at institutions with pro-AI policies', 'The integrity argument: If AI does the critical thinking, students don\'t build the analytical skills that education is for', 'The equity argument: GPT-4 costs £20/month — policies must account for students who cannot afford premium tools', 'The transparency principle: Whatever the rules, students must always disclose AI use — this is non-negotiable across all major policy frameworks', 'Assessment redesign: Instead of banning AI, build assessments that are AI-proof by design — oral presentations, process portfolios, in-class analysis'], callout: 'The International Baccalaureate now treats AI like a calculator — permitted with disclosure, banned in unsupported assessments. Cambridge, Oxford, and UK universities are watching this experiment closely.' },
    { type: 'activity', title: 'Acceptable Use Workshop', instructions: 'Collaboratively define acceptable use criteria for your school. Work through specific scenarios to build consensus.', steps: ['In groups of 4, discuss: What should students be allowed to use AI for?', 'Work through 8 scenarios your teacher provides — classify each as Acceptable, Unacceptable, or Depends', 'For each "Depends" scenario, define what conditions would make it acceptable', 'Draft 5 core principles of acceptable AI use in education', 'Share your principles with another group and negotiate any disagreements', 'As a class, vote on the final set of principles'] },
    { type: 'discussion', title: 'Drawing the Line', questions: [{ num: 1, text: 'If a student uses AI to generate ideas but writes everything themselves, should they still have to disclose AI use?' }, { num: 2, text: 'How should schools handle the fact that some students have access to paid AI tools (GPT-4) while others only have free versions?' }, { num: 3, text: 'A teacher uses AI to generate lesson plans and worksheets. Should the same rules that apply to students apply to teachers?' }] },
    { type: 'scenario', title: 'The Disclosure Decision', situation: 'You\'re in Year 13. You have a 2,000-word history essay due in three days on the causes of World War One. You\'ve read all the sources and formed your own argument. You used ChatGPT to help outline your three main sections (you rejected two of its suggested headings), and you used Grammarly to fix grammar in your final draft. Your essay is entirely your own argument, your own analysis, your own words — but the structure and grammar had AI assistance. Your school\'s policy says "disclose AI use" but doesn\'t explain how.', question: 'What do you write in your AI disclosure statement?', choices: [ { text: 'Disclose nothing — you wrote every word yourself, so it\'s not really AI use', outcome: 'Your teacher queries the unusually polished structure in a student who typically struggles with essay organisation. You can\'t explain your structuring process in a follow-up conversation. The ambiguity damages trust more than the original disclosure would have.' }, { text: 'Write a brief statement: "I used ChatGPT to help brainstorm an essay structure (I rejected most suggestions) and Grammarly for grammar checking. All analysis and writing is my own."', outcome: 'Your teacher marks your essay normally. In feedback, she notes your essay structure is particularly clear and asks if she can share your disclosure statement as a model for the class. You\'ve established yourself as a student who uses AI thoughtfully and transparently.' }, { text: 'Don\'t submit the essay — if the policy is unclear, you can\'t risk being accused of misconduct', outcome: 'You miss the deadline. When you explain your reasoning to your teacher, she points out that the policy\'s intent is transparency, not catch-and-punish. A brief disclosure would have been fine. You learn that when policy is unclear, asking your teacher is always better than self-imposing a late penalty.' } ] },
    { type: 'quiz', question: 'Why is transparency (disclosure of AI use) considered a "non-negotiable" principle across most AI policies?', options: ['It makes AI tools easier to use', 'It ensures AI tools are more accurate', 'It allows honest assessment of human vs. AI contribution', 'It prevents all forms of academic misconduct'], correct: 2, explanation: 'Regardless of where an institution draws the line on acceptable AI use, disclosure is essential because it allows fair assessment of what a student actually contributed versus what AI produced.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '📊', label: 'A spectrum, not a line', text: 'AI use ranges from inspiration (Level 1) to authorship (Level 4) — policy must address the contested middle ground' }, { icon: '⚖️', label: 'Skills vs. integrity', text: 'The IB\'s 2023 shift treats AI like a calculator — permitted with disclosure, banned in unsupported exams' }, { icon: '📢', label: 'Transparency is non-negotiable', text: 'Every major policy framework agrees: whatever the rules, disclosure of AI use must always be required' }] }
  ],

  19: [
    { type: 'hook', title: 'Drafting the Document', body: 'The UK Government\'s AI Safety Institute was established in November 2023 with a 12-page founding document. The EU AI Act runs to 459 pages. OpenAI\'s usage policy is 3 pages. The length, language, and structure of a policy document directly affects whether people actually read and follow it. Today, you will learn professional drafting techniques and write a formal AI acceptable use policy that is clear enough to follow and rigorous enough to enforce.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">12 pg</span><span class="sl">UK AI Safety Institute founding document</span></div><div class="hook-stat-mini"><span class="sv">459 pg</span><span class="sl">EU AI Act — the world\'s most comprehensive AI law</span></div><div class="hook-stat-mini"><span class="sv">3 pg</span><span class="sl">OpenAI\'s usage policy — brevity vs. comprehensiveness</span></div><div class="hook-stat-mini"><span class="sv">&lt;25</span><span class="sl">words per sentence — the plain English standard</span></div></div>' },
    { type: 'concept', title: 'Policy Document Structure', body: 'Professional policy documents follow established conventions that make them clear, authoritative, and enforceable. The UK Government\'s plain language guidance (GOV.UK style guide) requires all public-sector documents to pass a readability test — a standard that many school AI policies currently fail.', bullets: ['Title and version number: e.g. "AI Acceptable Use Policy v2.1 — Updated January 2025" tracks changes and signals currency', 'Purpose statement: One paragraph explaining why the policy exists and what problem it solves', 'Scope: Who does this apply to? Students only? Staff? Governors? In coursework, exams, or both?', 'Definitions: Define "generative AI", "AI-assisted work", "disclosure statement" — ambiguous terms create loopholes', 'Rules and principles: Numbered, unambiguous requirements — each rule should be independently testable', 'Enforcement: What happens at first, second, and third violation? Who decides? Is there an appeals process?', 'Review date: Commit to reviewing annually — AI changes faster than any other technology'], callout: 'The golden rule of policy writing: If a reasonable person could interpret a rule two different ways, the rule is not clear enough. Ambiguity is a loophole.' },
    { type: 'concept', title: 'Writing Effective Policy Language', body: 'Policy language must be precise without being impenetrable. The UK Civil Service\'s drafting standard is: "Write for a 16-year-old reading under time pressure." If your policy cannot pass that test, it will not be followed.', bullets: ['"Must" vs "should": Must = mandatory requirement; Should = recommendation. Never use "should" when you mean "must"', 'Ban vague terms: "Appropriate use", "excessive reliance", "responsible AI" are meaningless without definitions', 'Concrete examples: "For example, using Grammarly to check grammar is permitted at Level 2; using ChatGPT to write paragraphs is not"', 'Numbered sections: 3.1, 3.2, 3.3 makes specific rules quotable and referenceable in enforcement cases', 'Active voice: "Students must disclose AI use" not "AI use should be disclosed by students" — passive voice obscures responsibility'], callout: 'Bad: "Students should use AI responsibly." Good: "Students must disclose all AI tool use by appending an AI Use Statement to submitted work, specifying which tool was used and for what specific purpose."' },
    { type: 'activity', title: 'Draft Your Policy', instructions: 'Using the AI Policy Drafting Template from Resources, write a formal AI acceptable use policy for your school.', steps: ['Open the AI Policy Drafting Template resource', 'Write the Purpose statement (2-3 sentences)', 'Define the Scope (who, what, when)', 'Write Definitions for at least 5 key terms', 'Draft at least 8 numbered rules covering the spectrum of AI use', 'Write an Enforcement section with at least 3 levels of consequence', 'Set a Review Date and explain the review process', 'Peer review: Swap with a partner and identify any ambiguous language'] },
    { type: 'discussion', title: 'Language and Power', questions: [{ num: 1, text: 'Why is precise language so important in policy documents? What happens when rules are ambiguous?' }, { num: 2, text: 'Should policies be written in formal or informal language? What are the trade-offs of each?' }, { num: 3, text: 'How can you make a policy document that people actually read, rather than one that sits in a drawer?' }] },
    { type: 'scenario', title: 'The Ambiguous Rule', situation: 'Your school\'s AI policy contains this rule: "Students should not rely excessively on AI tools when completing assessed work." A student, Marcus, has submitted a business studies report. His teacher suspects the structure was AI-generated. Marcus says he "didn\'t rely excessively" — he used AI for headings but wrote all the content. The policy has no definition of "excessively" and no examples. The school now needs to decide whether Marcus has violated the policy.', question: 'What does this situation reveal about policy language — and how would you fix the rule?', choices: [ { text: 'Marcus has clearly broken the spirit of the rule. Refer him for misconduct — the intention of "no excessive reliance" is obvious', outcome: 'Marcus appeals. The appeals panel notes the word "excessively" is undefined and the policy uses "should" (recommendation) not "must" (requirement). The panel finds in Marcus\'s favour. The school rewrites the policy — but the damage to student-staff trust takes months to repair.' }, { text: 'No violation — the rule is too vague to enforce against any specific behaviour. Let it go and improve the policy for future', outcome: 'Marcus receives his mark. However, three other students in the same class now believe AI structure generation is permitted. The inconsistency spreads. The department head escalates to the head, who convenes an emergency policy review.' }, { text: 'Pause the grading, convene a policy review, rewrite the rule with a concrete definition before adjudicating Marcus\'s case', outcome: 'The review produces this replacement rule: "Students must not use AI to generate headers, section structures, or skeleton text for submitted work. Using AI to check grammar after completion is permitted." Marcus\'s case is reassessed under the new rule. The transparent process earns credibility across the student body.' } ] },
    { type: 'quiz', question: 'In professional policy drafting, what is the difference between "must" and "should"?', options: ['They mean the same thing', '"Must" is mandatory; "should" is recommended but not required', '"Should" is stronger than "must"', '"Must" is only used in legal documents'], correct: 1, explanation: 'In policy language, "must" creates a mandatory obligation, while "should" indicates a recommendation. This distinction is critical — ambiguity in policy language leads to inconsistent enforcement and successful appeals.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '📝', label: 'Structure matters', text: 'Professional policies follow: title/version, purpose, scope, definitions, numbered rules, enforcement, review date' }, { icon: '✍️', label: 'Every word counts', text: '"Must" vs. "should", no vague terms, concrete examples, numbered sections, active voice' }, { icon: '👥', label: 'Ambiguity is a loophole', text: 'If a reasonable person can interpret a rule two ways, it will be interpreted the convenient way — and appeals will succeed' }] }
  ],

  20: [
    { type: 'hook', title: 'Ratification', body: 'In 2024, the European Parliament voted 523 to 46 to adopt the AI Act — the world\'s first comprehensive AI law. But before that vote, the act went through 18 months of committee debates, 3,000 proposed amendments, and intense lobbying from tech companies. Democracy is messy, slow, and full of compromise. Today, your class will experience that process firsthand as you present, debate, and vote on your AI policies in a simulated governance process.<div class="hook-stats-row"><div class="hook-stat-mini"><span class="sv">523–46</span><span class="sl">European Parliament vote to adopt the AI Act</span></div><div class="hook-stat-mini"><span class="sv">3,000</span><span class="sl">proposed amendments before the final text</span></div><div class="hook-stat-mini"><span class="sv">18 mo</span><span class="sl">of committee debate after the Act was first drafted</span></div><div class="hook-stat-mini"><span class="sv">+40%</span><span class="sl">compliance when people helped write the rules</span></div></div>' },
    { type: 'concept', title: 'The Democratic Process', body: 'Policy ratification in democratic systems involves structured debate, amendment, and voting. The EU AI Act\'s journey — from a 2021 proposal to the 2024 vote — shows how democratic governance of technology works at scale. It also shows its limitations: by the time of the vote, the original draft did not mention ChatGPT, which launched three years after the proposal.', bullets: ['Presentation: Policy authors present their proposal with evidence, data, and worked examples', 'Committee stage: A smaller group examines specific clauses — the EU\'s IMCO committee proposed 450 of the 3,000 amendments alone', 'Debate: Open discussion — supporters and opponents both make their strongest case publicly', 'Amendment: Formal modification of specific clauses before final vote — this is where lobbying happens and compromises are struck', 'Vote: Simple majority (schools), qualified majority (EU Council), or supermajority depending on the rules', 'Implementation: Published, communicated to all stakeholders, with clear effective dates and review cycles'], callout: 'Real policy is rarely adopted as first drafted. The EU AI Act went through three complete rewrites. The amendment process is where policies become practical, balanced, and politically viable.' },
    { type: 'concept', title: 'Effective Persuasion', body: 'Presenting a policy proposal requires combining logical argument, evidence, and rhetorical skill. Cicero\'s three-part model — Ethos (credibility), Pathos (emotion), Logos (logic) — remains the foundation of effective public persuasion, including policy advocacy.', bullets: ['Lead with the problem: Anchor your case in a concrete harm — "Last year, three students were penalised under an unclear policy"', 'Present evidence: Cite the Jisc 2024 survey, the NIST accuracy report, or your own class audit findings', 'Acknowledge the strongest objection: "Critics argue this will restrict innovation — here is why that concern is addressed in clause 4.2..."', 'Make the ask specific: "We propose adding one sentence to Rule 3 to define \'excessive\' as more than 40% of submitted text"', 'Concede gracefully: Accepting a reasonable amendment in public builds far more credibility than defending a flawed clause'], callout: 'The most persuasive speakers acknowledge the strongest argument against their position and explain why, on balance, their proposal is still the right choice. This is called "steelmanning" your opposition.' },
    { type: 'activity', title: 'The Ratification Session', instructions: 'Present your group\'s AI policy to the class, debate amendments, and vote to ratify.', steps: ['Each group has 5 minutes to present their AI policy draft', 'After each presentation, the class has 5 minutes for questions and proposed amendments', 'Amendments are written on the board — each requires a seconder', 'The presenting group can accept or reject each amendment (with reasoning)', 'After all presentations, the class votes on which policy to adopt (or combines the best elements)', 'The ratified policy is finalised and the class signs it as a collective agreement'] },
    { type: 'discussion', title: 'Democracy and Technology', questions: [{ num: 1, text: 'Is democratic policy-making too slow for fast-moving technology? Should we give experts more power to decide?' }, { num: 2, text: 'How did the debate and amendment process change your original policy? Was it improved?' }, { num: 3, text: 'Should students have a genuine say in their school\'s AI policy, or should this be decided by leadership?' }] },
    { type: 'scenario', title: 'The Amendment Standoff', situation: 'Your group\'s AI policy is being debated. You have a clear rule (Rule 7): "Students must not use AI to generate section headings or essay structures for assessed work." Another group proposes an amendment: "Replace \'must not\' with \'should avoid where possible\' — it\'s too strict and will disadvantage struggling students." Five people have their hands up to speak. You have 90 seconds to decide whether to accept the amendment before the chair calls the vote.', question: 'What do you do?', choices: [ { text: 'Reject the amendment — "must not" is clear and enforceable. Weakening it creates ambiguity and loopholes', outcome: 'The vote is 14-9 to keep your original wording. Three students who voted against later tell you they felt their accessibility concerns were dismissed. Your policy passes but with lingering resentment. A teacher later notes that the "struggling students" argument deserved a more considered response.' }, { text: 'Accept the amendment in full — building consensus is more important than one clause', outcome: 'The policy passes unanimously. But two months later, a student successfully argues that submitting a fully AI-structured essay was covered by "should avoid where possible." The enforcement gap vindicates those who wanted clearer language.' }, { text: 'Counter-propose a middle ground: "Students must disclose AI-generated structure. Struggling students may request an approved AI-assisted drafting session with a teacher"', outcome: 'The counter-proposal wins 21-2. The dissenting votes were from students who thought the support session idea was too complicated to implement. Your amendment shows that debate is not always binary — a creative third option can command consensus that neither original position could achieve.' } ] },
    { type: 'quiz', question: 'Why is democratic involvement in policy creation important, beyond fairness?', options: ['It makes the process faster', 'People follow policies they helped create — it builds compliance', 'It eliminates the need for enforcement', 'It guarantees the best policy outcome'], correct: 1, explanation: 'Research shows that people are significantly more likely to follow policies they had a voice in creating. Democratic involvement builds ownership, understanding, and buy-in — not just legitimacy.' },
    { type: 'summary', title: 'Key Takeaways', points: [{ icon: '🗳️', label: 'Democracy is messy but vital', text: 'The EU AI Act needed 3,000 amendments and an 18-month committee stage — messy, but the process built legitimacy' }, { icon: '🎤', label: 'Steelman your opposition', text: 'Acknowledge the strongest argument against you and explain why your proposal is still better — this builds credibility' }, { icon: '📜', label: 'Ownership drives compliance', text: 'Studies show 40% higher compliance when people helped write the rules — democratic involvement isn\'t just fair, it\'s effective' }] }
  ]

};
